import { interval } from 'rxjs';
import { takeWhile } from 'rxjs/operators';
import * as i0 from "@angular/core";
import * as i1 from "@angular/common/http";
import * as i2 from "@angular/forms";
export class CaribbeanJobsPostsComponent {
    constructor(http, fb, baseUrl) {
        this.http = http;
        this.fb = fb;
        this.url = baseUrl + 'caribbeanjobsposts';
        this.jobPostsBeingFetched = false;
    }
    ngOnInit() {
    }
    async startFetchCaribbeanJobsPosts() {
        this.jobPostsBeingFetched = true;
        this.http.get(this.url + '/getcurrentposts')
            .subscribe({
            next: (result) => {
                if (result == true) {
                    //alert('Caribbeanjobs jobs posts fetched successfully!');
                }
                else {
                    //alert('Caribbeanjobs jobs posts could not be fetched.');
                }
            },
            error: (err) => {
                console.error(err);
            },
            complete: async () => {
                this.jobPostsBeingFetched = false;
                alert('done!');
            }
        });
        interval(2000)
            .pipe(takeWhile(() => this.jobPostsBeingFetched))
            .subscribe(() => {
            this.http.get(this.url + '/getlatestlogs')
                .subscribe({
                next: (result) => {
                    let scrollTextDiv = document.getElementById("scrollTextDiv");
                    if (scrollTextDiv != null && typeof result === "string") {
                        scrollTextDiv.innerText = result;
                        scrollTextDiv.scrollTop = scrollTextDiv.scrollHeight;
                    }
                },
                error: (err) => {
                    console.error(err);
                },
                complete: async () => {
                    console.log("job completed");
                }
            });
        });
    }
}
